Here are the public test cases for feature3_coverage_record_serialization:
{
  "description": "Serializes a coverage recording context (assembly, class and method identity plus a map of line id -> hit count) into a compact binary stream and reads it back. The round trip must preserve every field exactly: the number of recovered records, the three identity strings, and all line/hit pairs. Recovered hit pairs are reported in ascending line-id order.",
  "cases": [
    {
      "input": {
        "op": "roundtrip_hit_context",
        "assembly": "Asm",
        "class": "Ns.Type",
        "method": "DoWork",
        "hits": {
          "1": 15
        }
      },
      "expected_output": "count=1\nassembly=Asm\nclass=Ns.Type\nmethod=DoWork\nhits=1:15\n"
    },
    {
      "input": {
        "op": "roundtrip_hit_context",
        "assembly": "Sample.UnitTests",
        "class": "Sample.UnitTests.UnitTest1",
        "method": "Test",
        "hits": {
          "8": 1,
          "19": 50,
          "23": 2500050
        }
      },
      "expected_output": "count=1\nassembly=Sample.UnitTests\nclass=Sample.UnitTests.UnitTest1\nmethod=Test\nhits=8:1,19:50,23:2500050\n"
    }
  ]
}

Here are the public test cases for feature6_1_output_file_path:
{
  "description": "Resolves the output file path for a report. When no value is supplied the option falls back to a per-report default file name placed in the working directory. When a (possibly relative) value is supplied it is resolved to an absolute path against the working directory. The `role` selects which report's default name applies: coverage->coverage.json, clover->clover.xml, cobertura->cobertura.xml, ncover->coverage.xml, opencover->opencovercoverage.xml.",
  "cases": [
    {
      "input": {
        "op": "resolve_file_path",
        "role": "coverage",
        "workdir": "/current-directory",
        "value": null
      },
      "expected_output": "path=/current-directory/coverage.json\n"
    },
    {
      "input": {
        "op": "resolve_file_path",
        "role": "clover",
        "workdir": "/current-directory",
        "value": null
      },
      "expected_output": "path=/current-directory/clover.xml\n"
    },
    {
      "input": {
        "op": "resolve_file_path",
        "role": "cobertura",
        "workdir": "/current-directory",
        "value": null
      },
      "expected_output": "path=/current-directory/cobertura.xml\n"
    },
    {
      "input": {
        "op": "resolve_file_path",
        "role": "ncover",
        "workdir": "/current-directory",
        "value": null
      },
      "expected_output": "path=/current-directory/coverage.xml\n"
    },
    {
      "input": {
        "op": "resolve_file_path",
        "role": "opencover",
        "workdir": "/current-directory",
        "value": null
      },
      "expected_output": "path=/current-directory/opencovercoverage.xml\n"
    },
    {
      "input": {
        "op": "resolve_file_path",
        "role": "clover",
        "workdir": "/current-directory",
        "value": "folder/file.xml"
      },
      "expected_output": "path=/current-directory/folder/file.xml\n"
    }
  ]
}
